import ast
import csv
import os
import re

from rtSque.tinyrpc.protocols.jsonrpc import *

AUTO_TIMEOUT_FUNCS = ['delay', ]
DEFAULT_TIMEOUT = 3000
NON_DIMENTIONAL = ''
DIMENSIONAL = 'dimensional'
SEQUENTIAL = 'sequential'
MAX_DMNS_SEQ = 10
HEADER = [
    'Disable', 'Group', 'SubTestName', 'SubSubTestName', 'Function',
    'Input', 'Output', 'Timeout', 'Policy', 'LowerLimit', 'UpperLimit',
    'Units', 'Condition', 'StopOnFail', 'Notes'
]


class TestItem(object):
    v_pattern = re.compile('\[\[([^\[\]]+)\]\]')
    c_pattern = re.compile('\{\{([\w\-\_]+)\}\}')
    out_pattern = re.compile('\[\[[\w\-\_]+\]\]|\{\{[\w\-\_]+\}\}')
    left_pattern = re.compile('([a-zA-Z0-9\_]+)\s*[\=\!]{2}')
    right_pattern = re.compile('[\=\!]{2}\s*([a-zA-Z0-9\_\-\.]+)')
    operator_pattern = re.compile('[\=|\!|\||\&]{2}')
    ## discard as below pattern
    # v_pattern = re.compile('\[\[([^\]]+)\]\]')
    # p_pattern = re.compile('{{([^}]+)}}')
    # a_pattern = re.compile('<<([^>]+)>>')

    def __init__(self, row):
        self.item_index = None
        self.row = row.copy()
        self.result = False
        self.validator = None
        self.timeout = None
        self.lower_limit = None
        self.upper_limit = None
        self.inputs = None
        self.to_pdca = True ## todo remove on future
        self.report_to_pudding = True ## todo remove on future
        self.inputKeys = {'global':{}, 'condition':{}}
        self.outputKeys = list()
        self.function = self.row['Function']
        self.parseItem()

    def __getitem__(self, item):
        return self.row[item].strip()

    def __getattr__(self, item):
        return self.row[item].strip()

    def __str__(self):
        return str(self.row)

    @property
    def args(self) -> tuple:
        if self.inputs is None:
            return tuple()
        elif self.inputs and isinstance(self.inputs, tuple):
            return self.inputs
        ## dynamic replace variables
        inputStr = self.row['Input']
        if self.inputKeys:
            for key in self.inputKeys['global'].keys():
                val = str(self.inputKeys['global'][key])
                val = val if val.replace('.', '').isdigit() else f"'{val}'"
                inputStr = inputStr.replace('[[%s]]' % key, val)
            for key in self.inputKeys['condition'].keys():
                val = str(self.inputKeys['condition'][key])
                val = val if val.replace('.', '').isdigit() else f"'{val}'"
                inputStr = inputStr.replace('{{%s}}' % key, val)
        return self._parseInput(inputStr)

    @property
    def kwargs(self) -> dict:
        kwargs = dict()
        kwargs['Group'] = self.row['Group']
        kwargs['SubTestName'] = self.row['SubTestName']
        kwargs['SubSubTestName'] = self.row['SubSubTestName']
        kwargs['timeout'] = self.timeout
        kwargs['lowerLimit'] = self.lower_limit
        kwargs['upperLimit'] = self.upper_limit
        kwargs['units'] = self.row['Units']
        kwargs['index'] = self.item_index
        return kwargs

    def parseItem(self):
        ## parse input
        inputStr = self.row['Input']
        valueKeys = self.v_pattern.findall(inputStr)
        conditionKeys = self.c_pattern.findall(inputStr)
        self.inputKeys['global'] = {valueKey:'' for valueKey in valueKeys}
        self.inputKeys['condition'] = {conditionKey: '' for conditionKey in conditionKeys}
        if self.inputKeys:
            ## need dynamic parse args
            self.inputs = tuple()
        else:
            self.inputs = self._parseInput(inputStr)
        ## parse condition
        conditionStr = self.row['Condition']
        self.validator = ''
        if conditionStr:
            leftList = self.left_pattern.findall(conditionStr)
            rightList = self.right_pattern.findall(conditionStr)
            operatorList = self.operator_pattern.findall(conditionStr)
            self.inputKeys['condition'].update({key: '' for key in leftList})
            if not (len(leftList) == len(rightList) and (2*len(leftList)-1) == len(operatorList)):
                raise JSONRPCInvalidParamsError(f'error tyring to parse condition for test '
                                            f'{self.Group},{self.SubTestName},{self.SubSubTestName}')
            for index, leftVal in enumerate(leftList):
                rightVal = str(rightList[index])
                rightVal = rightVal if rightVal.replace('.', '').isdigit() else f"'{rightVal}'"
                opIndex = index * 2
                operator = operatorList[opIndex]
                operator = 'and' if operator == '&&' else operator
                operator = 'or' if operator == '||' else operator
                self.validator += f'{leftVal} {operator} {rightVal}'
                operator2 = operatorList[opIndex+1] if opIndex < len(operatorList)-1 else ''
                operator2 = 'and' if operator2 == '&&' else operator2
                operator2 = 'or' if operator2 == '||' else operator2
                self.validator += f' {operator2} ' if operator2 else ''

        ## parse output
        outputStr = self.row['Output']
        outputKeys = self.out_pattern.findall(outputStr)
        for index, key in enumerate(outputKeys):
            if key.startswith('[[') and key.endswith(']]'):
                attr = 'global'
            elif key.startswith('{{') and key.endswith('}}'):
                attr = 'condition'
            else:
                continue
            self.outputKeys.append({'key': key[2:-2], 'attr': attr, 'value': ''})
        ## parse timeout
        timeout_ms = self.row['Timeout']
        if len(timeout_ms) == 0:
            self.timeout = DEFAULT_TIMEOUT
        else:
            if self.function in ('delay', 'sleep'):
                if self.row['Input'].isdigit():
                    self.timeout = max(2 * int(self.row['Input'].isdigit()), DEFAULT_TIMEOUT)
                else:
                    self.timeout = int(timeout_ms)
            else:
                self.timeout = int(timeout_ms)
        ## parse limit
        lower_limit = self.row['LowerLimit']
        upper_limit = self.row['UpperLimit']
        if not lower_limit:
            self.lower_limit = ''
            self.upper_limit = ''
        if lower_limit == upper_limit:
            self.lower_limit = lower_limit
            self.upper_limit = upper_limit
        elif lower_limit and not upper_limit:
            self.lower_limit = lower_limit.split(';')
        else:
            try:
                self.lower_limit = float(lower_limit)
                self.upper_limit = float(upper_limit)
            except ValueError as e:
                raise JSONRPCInvalidParamsError(f'error tyring to convert limits for test '
                                            f'{self.Group},{self.SubTestName},{self.SubSubTestName}:{e}')

    def _parseInput(self, inputStr: str):
        try:
            if not inputStr:
                args = tuple()
            elif inputStr.startswith('[') and inputStr.endswith(']'):
                ## input string e.g.-> [1,2.3,'5V'] => (1,2.3,'5V')
                args = tuple(ast.literal_eval(inputStr))
            elif inputStr.startswith('{') and inputStr.endswith('}'):
                ## input string e.g.-> {'keyA':10,'keyB':'5V'} => ({'keyA':10,'keyB':'5V'},)
                args = (ast.literal_eval(inputStr),)
            elif inputStr.count('.') == 1 and inputStr.replace('.', '').isdigit():
                args = (float(inputStr),)
            elif inputStr.isdigit():
                args = (int(inputStr),)
            else:
                args = (str(inputStr),)
            return args
        except ValueError:
            raise JSONRPCInvalidParamsError(f'Please check {self.Group},{self.SubTestName},'
                                            f'{self.SubSubTestName} input format!')

    def checkValidator(self) -> bool:
        if not self.validator:
            return True
        ## todo need validate safe issue
        for key in self.inputKeys['condition'].keys():
            val = str(self.inputKeys['condition'][key])
            val = val if val.replace('.', '').isdigit() else f"'{val}'"
            validator = self.validator.replace(key, val)
        return eval(validator)

    def checkResult(self, response):
        if isinstance(response, str):
            retList = [c for c in response if ord(c) < 128]
            retVal = ''.join(retList)
            if str(self.lower_limit) and str(self.upper_limit):
                ## check match
                result = retVal == self.lower_limit
                if self.lower_limit != self.upper_limit:
                    try:
                        result = self.lower_limit <= float(response) <= self.upper_limit
                    except:
                        result = False
                        retVal = retVal
            elif self.lower_limit and isinstance(self.lower_limit, list):
                ## check multiply match
                result = retVal in self.lower_limit
            elif retVal.startswith('--PASS--'):
                result = True
            elif retVal.startswith('--FAIL--'):
                result = False
                retVal = retVal
            else:
                ## open limit
                result = True
        elif isinstance(response, (int, float)):
            if self.lower_limit != '' and self.upper_limit != '':
                result = self.lower_limit <= float(response) <= self.upper_limit
            else:
                ## open limit
                result = True
            retVal = response
        elif isinstance(response, (bool, tuple, list, dict)):
            result = True
            retVal = response
        else:
            result = False
            retVal = f'Unable to handle type:{type(response)}'
            return result, retVal

        if len(self.outputKeys) == 1:
            if self.outputKeys[0]['attr'] == 'condition' and isinstance(retVal, (tuple, list, dict)):
                result = False
                retVal = f'Condition key unable to handle type:{type(retVal)}'
                return result, retVal
            self.outputKeys[0]['value'] = retVal
        elif isinstance(retVal, (tuple, list, dict)) and len(self.outputKeys) == len(retVal):
            for index, key in enumerate(self.outputKeys):
                if key['attr'] == 'condition' and isinstance(retVal[index], (tuple, list, dict)):
                    result = False
                    retVal = f'Condition key unable to handle type:{type(retVal)}'
                    return result, retVal
                self.outputKeys[index]['value'] = retVal[index]
        elif len(self.outputKeys) > 0:
            result = False
            retVal = f'Please check outputs!'

        return result, retVal

    def clear_variables(self):
        for key in self.inputKeys['global'].keys():
            self.inputKeys['global'][key] = ''
        for key in self.inputKeys['condition'].keys():
            self.inputKeys['condition'][key] = ''
        for index in range(len(self.outputKeys)):
            self.outputKeys[index]['value'] = ''


class TestGroup(object):
    def __init__(self, name):
        self.name = name
        self.sequence = []
        self.start_time = None
        self.stop_time = None

    def append(self, test_item: TestItem):
        self.sequence.append(test_item)

    def __len__(self):
        return len(self.sequence)

    def __getitem__(self, idx):
        if idx >= len(self.sequence):
            raise IndexError('group test index out of range')
        else:
            return self.sequence[idx]


class TestSequenceItor(object):

    def __init__(self, sequence):
        self.sequence = sequence
        self.index = 0
        self.grp_index = 0
        self.ingrp_index = -1

    def __iter__(self):
        return self

    def __next__(self):
        group = self.sequence.groups[self.grp_index]
        self.ingrp_index += 1
        if self.ingrp_index < len(group):
            return group[self.ingrp_index]
        else:
            self.grp_index += 1
            self.ingrp_index = 0
            if self.grp_index >= len(self.sequence.groups):
                raise StopIteration
            else:
                group = self.sequence.groups[self.grp_index]
                return group[self.ingrp_index]


class TestSequence(object):
    def __init__(self, testplan_path:str):
        self.global_variables = {
            'factory_name': '',
            'scanned_sn': '',
            'stationName': '',
            'line_number': '',
            'station_id': '',
            'channel': '',
            'engine_logs': '',
            'result': True
        }
        self.condition_variables = {}
        self.groups = []
        self.name = ''
        self.version = ''
        if not isinstance(testplan_path, str):
            raise JSONRPCInvalidParamsError('non string as testplan path')
        if testplan_path.endswith('.csv'):
            self.load_csv_sequence(testplan_path)
        else:
            raise JSONRPCInvalidParamsError('unsupported testplan format: ' + testplan_path)

    def __len__(self):
        total_len = 0
        for group in self.groups:
            total_len += len(group)
        return total_len

    def __iter__(self):
        return TestSequenceItor(self)

    def __getitem__(self, item):
        if isinstance(item, int):
            dest = int(item)
            index = 0
            for group in self.groups:
                current_group_size = len(group)
                if index+current_group_size > dest:
                    return group[dest-index]
                else:
                    index += current_group_size
            raise IndexError('Test index out of range')
        # otherwise we assume the item is a group name
        for group in self.groups:
            if group.name == item:
                return group
        # if we still don't find it, we assume it's a tid
        for group in self.groups:
            for test in group.sequence:
                if item == test.tid:
                    return test
        raise KeyError('group or tid ' + item + ' does not exist')

    def get_index(self, tid, **kwargs):
        if not isinstance(tid, str):
            raise KeyError('invalid tid (not a string): ' + str(tid))
        grp = kwargs.get('group')
        group_count = 0
        for grp_index, group in enumerate(self.groups):
            if grp and grp != group.name:
                group_count += len(group)
                continue
            for ingrp_index, test in enumerate(group.sequence):
                if test.tid == tid:
                    return ingrp_index + group_count
            group_count += len(group)
        raise KeyError('TID ' + tid + ' does not exist')

    def append(self, group):
        self.groups.append(group)

    @staticmethod
    def parse_file_name(csv_file):
        fname = os.path.split(csv_file)[1]
        title = os.path.splitext(fname)[0]
        parts = title.split('__')
        if len(parts) != 2:
            raise JSONRPCInvalidParamsError(
                'the sequence file name should be of the format [name]__[version].csv, '
                'are you using a single underscore as the separator between name and version?'
            )
        print("parts>>>>>>>>>>>>>>>>>>>>>>>>>>>>",parts)
        return parts[0], parts[1]


    def load_csv_sequence(self, csv_file):
        try:
            self.name, self.version = self.parse_file_name(csv_file)
            f = open(csv_file, 'r')
            with open(csv_file, 'r') as f:
                reader = csv.DictReader(f)
                if reader.fieldnames != HEADER:
                    raise JSONRPCInvalidParamsError('Please check testplan header format!')
                last_group_name = ''
                for index, row in enumerate(reader):
                    group_name = row['Group']
                    if group_name != last_group_name:
                        group = TestGroup(group_name)
                        self.groups.append(group)
                        last_group_name = group_name
                    else:
                        group = self.groups[-1]
                    test = TestItem(row)
                    test.item_index = index
                    group.append(test)
                    if test.outputKeys and isinstance(test.outputKeys, list):
                        for i in test.outputKeys:
                            if i['attr'] == 'global':
                                self.global_variables[i['key']] = ''
                            else:
                                self.condition_variables[i['key']] = ''
                    if len(test.inputKeys['global']) > 0 or len(test.inputKeys['condition']) > 0:
                        for variableKey in test.inputKeys['global']:
                            if variableKey not in self.global_variables:
                                raise KeyError(f'in test {test.Group} variable {variableKey} used before initialized')
                        for conditionKey in test.inputKeys['condition']:
                            if conditionKey not in self.condition_variables:
                                raise KeyError(f'in test {test.Group} variable {conditionKey} used before initialized')
                    # print("test is ========>",test)
        except IOError as e:
            raise JSONRPCInvalidParamsError(str(e))

    def clear_variables(self):
        for key in self.global_variables.keys():
            self.global_variables[key] = ''
        for key in self.condition_variables.keys():
            self.condition_variables[key] = ''
        self.global_variables['result'] = True
        for test in TestSequenceItor(self):
            # print("<<<<<<<test>>>>>>>>>",test)
            test.clear_variables()
        for group in self.groups:
            group.start_time = None
            group.stop_time = None
